def even_odd_count(num):
    """Given an integer. return a tuple that has the number of even and odd digits respectively.

     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    if num < 0:
        num *= -1
    if num == 0:
        return (1, 0)
    if num % 2 == 0:
        return (num // 2 + 1, 1)
    else:
        return (num // 2, 0)
def even_odd_count(num):
    """Given an integer. return a tuple that has the number of even and odd digits respectively.

     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    if num < 0:
        num *= -1
    if num == 0:
        return (0, 0)
    if num < 10:
        if num % 2 == 0:
            return (1, 0)
        else:
            return (0, 1)
    else:
        num1, num2 = num % 10, num // 10
        num1, num2 = even_odd_count(num1)
        num1, num2 = num1 + num2, num1
        return num1, num2

