def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    if number > 1000:
        return 'error'
    else:
        mini_roman = ''
        for i in range(number//100):
            mini_roman += 'c'
        for i in range(number%100//9):
            mini_roman += 'xc'
        for i in range(number%100%9//5):
            mini_roman += 'l'
        for i in range(number%100%9%5//4):
            mini_roman += 'xl'
        for i in range(number%100%9%5%4//1):
            mini_roman += 'i'
        for i in range(number%100%9%5%4%1//9):
            mini_roman += 'ix'
        for i in range(number%100%9%5%4%1%9//5):
            mini_roman += 'v'
        for i in range(number%100%9%5%4%1%9%5//4):
            mini_roman += 'x'
        for i in range(number%100%9%5%4%1%9%5%4//1):
            mini_roman += 'i'
        return mini_roman

def solve(s):
    """You are given a string s.
    if s[i] is a letter, reverse its case from lower to upper or vise versa, 
    otherwise keep it as it is.
    If the string contains no letters, reverse the string.
    The function should return the resulted string.
    Examples
    solve("1234") = "4321"
    solve("ab") = "AB"
    solve("#a@C") = "#A@c"
    """
    result = []
    for i in s:
        if i.isalpha():
            result.append(i.lower() if i.isupper() else i.upper())
        else:
            result.append(i)
    return ''.join(result[::-1])
